"use client";

import { useState, useRef, useEffect } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import { getNextStep } from "@/content";
import { triggerShake, getRandomComplete, getRandomEncourage } from "@/lib/learningMessages";

// ===== 饼图常量 =====
const PIE_CX = 110;
const PIE_CY = 110;
const PIE_R = 88;
const PIE_SIZE = 220;

// 三种切法：份数 + 高亮一份时显示的等式
const CUTS = [
  { n: 2, label: "切一半", eq: "1/2 = 0.5" },
  { n: 4, label: "切四份", eq: "1/4 = 0.25" },
  { n: 10, label: "切十分", eq: "1/10 = 0.1" },
] as const;

// 配对数据：分数 ↔ 小数
const PAIRS = [
  { fraction: "1/2", decimal: "0.5" },
  { fraction: "1/4", decimal: "0.25" },
  { fraction: "1/10", decimal: "0.1" },
  { fraction: "3/10", decimal: "0.3" },
];
// 右列小数（打乱顺序）
const RIGHT_DECIMALS = ["0.25", "0.1", "0.5", "0.3"];

type Phase = "discover" | "match" | "done";
interface Line {
  x1: number;
  y1: number;
  x2: number;
  y2: number;
}

/** 生成饼图扇形路径（角度为弧度，从 startAngle 顺时针到 endAngle） */
function slicePath(
  cx: number,
  cy: number,
  r: number,
  startAngle: number,
  endAngle: number
): string {
  const x1 = cx + r * Math.cos(startAngle);
  const y1 = cy + r * Math.sin(startAngle);
  const x2 = cx + r * Math.cos(endAngle);
  const y2 = cy + r * Math.sin(endAngle);
  const largeArc = endAngle - startAngle > Math.PI ? 1 : 0;
  return `M ${cx} ${cy} L ${x1} ${y1} A ${r} ${r} 0 ${largeArc} 1 ${x2} ${y2} Z`;
}

export default function TransformPage() {
  const [phase, setPhase] = useState<Phase>("discover");
  const [cutN, setCutN] = useState<number>(0); // 0 = 整圆
  const [tried, setTried] = useState<boolean[]>([false, false, false]);

  const [matched, setMatched] = useState<boolean[]>(PAIRS.map(() => false));
  const [selected, setSelected] = useState<{
    side: "left" | "right";
    key: string;
  } | null>(null);
  const [lines, setLines] = useState<Line[]>([]);
  const [completeMsg, setCompleteMsg] = useState("");
  useEffect(() => { setCompleteMsg(getRandomComplete()); }, []);
  const [encourage, setEncourage] = useState<string | null>(null);
  const encourageTimer = useRef<ReturnType<typeof setTimeout> | null>(null);

  const showEncourage = () => {
    setEncourage(getRandomEncourage());
    if (encourageTimer.current) clearTimeout(encourageTimer.current);
    encourageTimer.current = setTimeout(() => setEncourage(null), 1800);
  };

  const leftRefs = useRef<Record<string, HTMLButtonElement | null>>({});
  const rightRefs = useRef<Record<string, HTMLButtonElement | null>>({});
  const boardRef = useRef<HTMLDivElement | null>(null);

  const allTried = tried.every(Boolean);
  const allMatched = matched.every(Boolean);

  // ===== 阶段 1：切饼图 =====
  const handleCut = (idx: number) => {
    const cut = CUTS[idx];
    setCutN(cut.n);
    setTried((prev) => prev.map((v, i) => (i === idx ? true : v)));
  };

  const currentEq =
    CUTS.find((c) => c.n === cutN)?.eq ?? "整圆 = 1";

  // ===== 阶段 2：配对 =====
  const pairIndexOfLeft = (fraction: string) =>
    PAIRS.findIndex((p) => p.fraction === fraction);
  const pairIndexOfRight = (decimal: string) =>
    PAIRS.findIndex((p) => p.decimal === decimal);

  const handlePick = (side: "left" | "right", key: string) => {
    const idx =
      side === "left" ? pairIndexOfLeft(key) : pairIndexOfRight(key);
    if (idx < 0 || matched[idx]) return; // 已配对，忽略

    if (selected === null) {
      setSelected({ side, key });
      return;
    }

    // 同列：切换选择（再次点击同一个则取消）
    if (selected.side === side) {
      setSelected(selected.key === key ? null : { side, key });
      return;
    }

    // 异列：尝试配对
    const leftKey = selected.side === "left" ? selected.key : key;
    const rightKey = selected.side === "right" ? selected.key : key;
    const pairIdx = PAIRS.findIndex(
      (p) => p.fraction === leftKey && p.decimal === rightKey
    );

    if (pairIdx >= 0) {
      // 配对正确
      setMatched((prev) =>
        prev.map((m, i) => (i === pairIdx ? true : m))
      );
      setSelected(null);
    } else {
      // 配对错误：抖动当前点击项
      const el =
        side === "left"
          ? leftRefs.current[key]
          : rightRefs.current[key];
      triggerShake(el);
      showEncourage();
    }
  };

  // 计算已配对项之间的连线
  useEffect(() => {
    if (phase !== "match") return;
    const compute = () => {
      const board = boardRef.current;
      if (!board) {
        setLines([]);
        return;
      }
      const br = board.getBoundingClientRect();
      const next: Line[] = [];
      PAIRS.forEach((p, i) => {
        if (!matched[i]) return;
        const le = leftRefs.current[p.fraction];
        const re = rightRefs.current[p.decimal];
        if (le && re) {
          const lr = le.getBoundingClientRect();
          const rr = re.getBoundingClientRect();
          next.push({
            x1: lr.right - br.left,
            y1: lr.top + lr.height / 2 - br.top,
            x2: rr.left - br.left,
            y2: rr.top + rr.height / 2 - br.top,
          });
        }
      });
      setLines(next);
    };
    compute();
    window.addEventListener("resize", compute);
    return () => window.removeEventListener("resize", compute);
  }, [matched, phase]);

  const nextStep = getNextStep("decimal", "transform");

  return (
    <StepShell topicId="decimal" stepId="transform">
      <div className="space-y-6">
        {/* ===== 阶段 1：发现关系 ===== */}
        {phase === "discover" && (
          <>
            <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-soft)] p-4 text-center">
              <p className="text-[var(--text)]">
                🥧 把一个圆切成几份，看看小数和分数的关系
              </p>
              <p className="mt-1 text-sm text-[var(--text-secondary)]">
                点击按钮切一切，高亮的部分就是对应的分数
              </p>
            </div>

            <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
              {/* 饼图 */}
              <div className="flex flex-col items-center">
                <svg
                  viewBox={`0 0 ${PIE_SIZE} ${PIE_SIZE}`}
                  className="w-44"
                  style={{ height: "auto" }}
                >
                  {cutN === 0 ? (
                    <circle
                      cx={PIE_CX}
                      cy={PIE_CY}
                      r={PIE_R}
                      style={{ fill: "var(--primary-light)", stroke: "white", strokeWidth: 2 }}
                    />
                  ) : (
                    Array.from({ length: cutN }).map((_, k) => {
                      const a0 = -Math.PI / 2 + (k * 2 * Math.PI) / cutN;
                      const a1 = -Math.PI / 2 + ((k + 1) * 2 * Math.PI) / cutN;
                      return (
                        <path
                          key={k}
                          d={slicePath(PIE_CX, PIE_CY, PIE_R, a0, a1)}
                          style={{
                            fill: k === 0 ? "var(--accent)" : "var(--primary-light)",
                            stroke: "white",
                            strokeWidth: 2,
                          }}
                        />
                      );
                    })
                  )}
                </svg>

                {/* 等式 */}
                <div className="mt-4">
                  <span
                    className="inline-block rounded-full px-5 py-2 text-lg font-extrabold text-white shadow-[var(--shadow-sm)] animate-float-in"
                    style={{ backgroundColor: "var(--accent)" }}
                    key={currentEq}
                  >
                    {currentEq}
                  </span>
                </div>
              </div>

              {/* 切分按钮 */}
              <div className="mt-6 flex flex-wrap justify-center gap-3">
                {CUTS.map((cut, idx) => (
                  <button
                    key={cut.n}
                    onClick={() => handleCut(idx)}
                    className={`rounded-full px-5 py-2.5 text-sm font-semibold transition-all hover:scale-105 ${
                      cutN === cut.n
                        ? "text-white shadow-[var(--shadow-accent)]"
                        : "text-[var(--text)]"
                    }`}
                    style={{
                      backgroundColor:
                        cutN === cut.n ? "var(--accent)" : "var(--bg-soft)",
                      border: `2px solid ${cutN === cut.n ? "var(--accent)" : "var(--border)"}`,
                    }}
                  >
                    {tried[idx] ? "✓ " : ""}
                    {cut.label}
                  </button>
                ))}
              </div>

              {/* 进度提示 */}
              <div className="mt-4 text-center">
                <p className="text-xs text-[var(--text-muted)]">
                  已发现 {tried.filter(Boolean).length} / {CUTS.length} 种关系
                </p>
              </div>
            </div>

            {/* 进入配对练习 */}
            <div className="flex flex-col items-center gap-2">
              <button
                onClick={() => setPhase("match")}
                disabled={!allTried}
                className="rounded-full px-6 py-3 font-semibold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105 disabled:cursor-not-allowed disabled:opacity-30"
                style={{ backgroundColor: "var(--accent)" }}
              >
                开始配对练习 →
              </button>
              {!allTried && (
                <p className="text-xs text-[var(--text-muted)]">
                  先把三种切法都试一试吧！
                </p>
              )}
            </div>
          </>
        )}

        {/* ===== 阶段 2：配对练习 ===== */}
        {phase === "match" && (
          <>
            <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-soft)] p-4 text-center">
              <p className="text-[var(--text)]">
                🔗 把相等的分数和小数连起来
              </p>
              <p className="mt-1 text-sm text-[var(--text-secondary)]">
                点左边一个，再点右边一个进行配对
              </p>
            </div>

            {/* 回顾提示 */}
            <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-3 text-center shadow-[var(--shadow-sm)]">
              <p className="text-xs text-[var(--text-secondary)]">
                💡 回顾：1/2 = 0.5　·　1/4 = 0.25　·　1/10 = 0.1　·　3/10 就是 3 个 0.1 = 0.3
              </p>
            </div>

            <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
              <div className="mb-3 text-center text-xs text-[var(--text-muted)]">
                {encourage ? (
                  <span
                    className="text-sm font-medium animate-float-in"
                    style={{ color: "var(--signal-shake)" }}
                  >
                    {encourage}
                  </span>
                ) : (
                  <span>已配对 {matched.filter(Boolean).length} / {PAIRS.length}</span>
                )}
              </div>

              <div ref={boardRef} className="relative">
                {/* 连线层 */}
                <svg
                  className="pointer-events-none absolute inset-0 h-full w-full"
                  style={{ overflow: "visible" }}
                >
                  {lines.map((l, i) => (
                    <line
                      key={i}
                      x1={l.x1}
                      y1={l.y1}
                      x2={l.x2}
                      y2={l.y2}
                      style={{
                        stroke: "var(--signal-success)",
                        strokeWidth: 3,
                        strokeLinecap: "round",
                      }}
                    />
                  ))}
                </svg>

                <div className="grid grid-cols-2 gap-10">
                  {/* 左列：分数 */}
                  <div className="flex flex-col gap-3">
                    {PAIRS.map((p) => {
                      const idx = pairIndexOfLeft(p.fraction);
                      const isMatched = matched[idx];
                      const isSelected =
                        selected?.side === "left" && selected.key === p.fraction;
                      return (
                        <button
                          key={p.fraction}
                          ref={(el) => {
                            leftRefs.current[p.fraction] = el;
                          }}
                          onClick={() => handlePick("left", p.fraction)}
                          disabled={isMatched}
                          className={`rounded-xl px-4 py-4 text-lg font-bold transition-all ${
                            isMatched
                              ? "cursor-default text-white"
                              : "cursor-pointer hover:scale-105"
                          } ${
                            isSelected && !isMatched
                              ? "text-white shadow-[var(--shadow-accent)]"
                              : ""
                          }`}
                          style={{
                            backgroundColor: isMatched
                              ? "var(--signal-success)"
                              : isSelected
                              ? "var(--accent)"
                              : "var(--bg-soft)",
                            border: `2px solid ${
                              isMatched
                                ? "var(--signal-success)"
                                : isSelected
                                ? "var(--accent)"
                                : "var(--border)"
                            }`,
                          }}
                        >
                          {p.fraction}
                          {isMatched && " ✓"}
                        </button>
                      );
                    })}
                  </div>

                  {/* 右列：小数 */}
                  <div className="flex flex-col gap-3">
                    {RIGHT_DECIMALS.map((d) => {
                      const idx = pairIndexOfRight(d);
                      const isMatched = matched[idx];
                      const isSelected =
                        selected?.side === "right" && selected.key === d;
                      return (
                        <button
                          key={d}
                          ref={(el) => {
                            rightRefs.current[d] = el;
                          }}
                          onClick={() => handlePick("right", d)}
                          disabled={isMatched}
                          className={`rounded-xl px-4 py-4 text-lg font-bold transition-all ${
                            isMatched
                              ? "cursor-default text-white"
                              : "cursor-pointer hover:scale-105"
                          } ${
                            isSelected && !isMatched
                              ? "text-white shadow-[var(--shadow-accent)]"
                              : ""
                          }`}
                          style={{
                            backgroundColor: isMatched
                              ? "var(--signal-success)"
                              : isSelected
                              ? "var(--accent)"
                              : "var(--bg-soft)",
                            border: `2px solid ${
                              isMatched
                                ? "var(--signal-success)"
                                : isSelected
                                ? "var(--accent)"
                                : "var(--border)"
                            }`,
                          }}
                        >
                          {d}
                          {isMatched && " ✓"}
                        </button>
                      );
                    })}
                  </div>
                </div>
              </div>

              {/* 完成检测后自动进入完成态 */}
              {allMatched && (
                <button
                  onClick={() => setPhase("done")}
                  className="mx-auto mt-5 block rounded-full px-6 py-3 font-semibold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
                  style={{ backgroundColor: "var(--accent)" }}
                >
                  查看结果 →
                </button>
              )}
            </div>
          </>
        )}

        {/* ===== 完成阶段 ===== */}
        {phase === "done" && (
          <div className="space-y-4">
            <div className="rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-md)] animate-float-in">
              <div className="mb-2 text-4xl">🌟</div>
              <p className="text-lg font-semibold text-[var(--text)]">
                {completeMsg}
              </p>
              <p className="mt-2 text-sm text-[var(--text-secondary)]">
                你发现了小数和分数的秘密：它们是同一个数的不同写法！
              </p>
              {/* 关系总结 */}
              <div className="mt-4 flex flex-wrap justify-center gap-2">
                {PAIRS.map((p) => (
                  <span
                    key={p.fraction}
                    className="rounded-full px-3 py-1 text-sm font-bold text-white"
                    style={{ backgroundColor: "var(--signal-success)" }}
                  >
                    {p.fraction} = {p.decimal}
                  </span>
                ))}
              </div>
            </div>

            <div className="flex justify-center gap-4">
              <button
                onClick={() => {
                  setPhase("match");
                  setMatched(PAIRS.map(() => false));
                  setSelected(null);
                  setLines([]);
                }}
                className="rounded-full border border-[var(--border)] px-6 py-3 font-medium text-[var(--text-secondary)] transition-all hover:bg-[var(--bg-soft)]"
              >
                再玩一次
              </button>
              {nextStep && (
                <Link
                  href={nextStep.path}
                  className="rounded-full bg-[var(--accent)] px-6 py-3 font-semibold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
                >
                  下一步：{nextStep.label} →
                </Link>
              )}
            </div>
          </div>
        )}
      </div>
    </StepShell>
  );
}
